// src/pages/LeaveRequests.js
import React, { useState } from 'react';
import { useApp } from '../context/AppContext';

export default function LeaveRequests() {
  const {
    leaveRequests,
    updateLeaveStatus,
    updateSubstitute,
    acceptSubstitute,
    currentUser
  } = useApp();

  const [filter, setFilter] = useState('all');
  const [expanded, setExpanded] = useState(null);

  const isAdmin = currentUser.role === 'admin';

  const filtered = leaveRequests
    .filter(r => (filter === 'all' ? true : r.status === filter))
    .sort((a, b) => b.id - a.id);

  return (
    <div style={styles.container}>
      <h1 style={styles.title}>📋 Leave Requests</h1>

      {/* Filter Tabs */}
      <div style={styles.tabs}>
        {['all', 'pending', 'approved', 'rejected'].map(f => (
          <button
            key={f}
            onClick={() => setFilter(f)}
            style={{ ...styles.tab, ...(filter === f ? styles.tabActive : {}) }}
          >
            {f.toUpperCase()}
          </button>
        ))}
      </div>

      <div style={styles.list}>
        {filtered.map(req => (
          <div key={req.id} style={styles.card}>
            <div style={styles.cardHeader}>
              <div>
                <div style={styles.teacherName}>{req.teacherName}</div>
                <div>📅 {req.fromDate} → {req.toDate}</div>
                <div>📝 {req.reason}</div>
              </div>

              <div style={styles.rightActions}>
                <StatusBadge status={req.status} />

                {isAdmin && req.status === 'pending' && (
                  <div style={styles.actionBtns}>
                    <button
                      style={styles.approveBtn}
                      onClick={() => updateLeaveStatus(req.id, 'approved')}
                    >
                      Approve
                    </button>
                    <button
                      style={styles.rejectBtn}
                      onClick={() => updateLeaveStatus(req.id, 'rejected')}
                    >
                      Reject
                    </button>
                  </div>
                )}

                {req.substituteRequests.length > 0 && (
                  <button
                    style={styles.detailBtn}
                    onClick={() =>
                      setExpanded(expanded === req.id ? null : req.id)
                    }
                  >
                    {expanded === req.id ? 'Hide' : 'Show'} Substitutes
                  </button>
                )}
              </div>
            </div>

            {/* Substitute Section */}
            {expanded === req.id && (
              <div style={styles.subSection}>
                {req.substituteRequests.map((sub, idx) => (
                  <div key={idx} style={styles.subCard}>
                    <div>
                      {sub.date} | {sub.day} | P{sub.period} | {sub.time} | Class {sub.class}
                    </div>

                    <div style={{ marginTop: 8 }}>
                      {sub.freeTeachers.length === 0 ? (
                        <span style={styles.noSub}>No available teacher</span>
                      ) : sub.assignedTeacherId ? (
                        <span style={styles.assigned}>
                          ✔ Assigned to{' '}
                          {sub.freeTeachers.find(
                            t => t.id === sub.assignedTeacherId
                          )?.name}
                        </span>
                      ) : sub.freeTeachers.some(
                          t => t.id === currentUser.id
                        ) ? (
                        <button
                          style={styles.acceptBtn}
                          onClick={() =>
                            acceptSubstitute(req.id, idx, currentUser.id)
                          }
                        >
                          Accept
                        </button>
                      ) : (
                        <span style={styles.waiting}>
                          Waiting for teacher
                        </span>
                      )}
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );
}

function StatusBadge({ status }) {
  const map = {
    pending: { bg: '#fef3c7', label: 'Pending' },
    approved: { bg: '#d1fae5', label: 'Approved' },
    rejected: { bg: '#fee2e2', label: 'Rejected' },
  };
  const s = map[status] || map.pending;
  return (
    <span style={{ background: s.bg, padding: '6px 14px', borderRadius: 20 }}>
      {s.label}
    </span>
  );
}

const styles = {
  container: { padding: 30, maxWidth: 1000, margin: '0 auto' },
  title: { fontSize: 26, fontWeight: 800, marginBottom: 20 },
  tabs: { display: 'flex', gap: 10, marginBottom: 20 },
  tab: {
    padding: '8px 18px',
    borderRadius: 8,
    border: '1px solid #ccc',
    cursor: 'pointer',
  },
  tabActive: { background: '#1e293b', color: '#fff' },
  list: { display: 'flex', flexDirection: 'column', gap: 16 },
  card: {
    background: '#fff',
    padding: 20,
    borderRadius: 12,
    boxShadow: '0 2px 10px rgba(0,0,0,0.05)',
  },
  cardHeader: {
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'flex-start',
  },
  teacherName: { fontWeight: 700, fontSize: 16 },
  rightActions: { display: 'flex', flexDirection: 'column', gap: 10 },
  actionBtns: { display: 'flex', gap: 8 },
  approveBtn: {
    background: '#10b981',
    color: '#fff',
    border: 'none',
    padding: '6px 14px',
    borderRadius: 6,
    cursor: 'pointer',
  },
  rejectBtn: {
    background: '#ef4444',
    color: '#fff',
    border: 'none',
    padding: '6px 14px',
    borderRadius: 6,
    cursor: 'pointer',
  },
  detailBtn: {
    background: '#f1f5f9',
    border: '1px solid #ccc',
    padding: '5px 10px',
    borderRadius: 6,
    cursor: 'pointer',
  },
  subSection: { marginTop: 15 },
  subCard: {
    border: '1px solid #e5e7eb',
    padding: 12,
    borderRadius: 8,
    marginBottom: 10,
  },
  acceptBtn: {
    background: '#16a34a',
    color: '#fff',
    border: 'none',
    padding: '6px 14px',
    borderRadius: 6,
    cursor: 'pointer',
  },
  assigned: { color: 'green', fontWeight: 600 },
  waiting: { color: '#f59e0b', fontWeight: 600 },
  noSub: { color: '#dc2626', fontWeight: 600 },
};
